toolArgs.file_text:
/* ─── Layout Shell ─── */
.chat-container {
    display: flex;
    height: 100vh;
    overflow: hidden;
    font-family: -apple-system, BlinkMacSystemFont, "Segoe UI", Roboto, sans-serif;
    color: #1d1c1d;
}

/* ─── Left Sidebar ─── */
.chat-sidebar {
    width: 20%;
    min-width: 200px;
    background: #3f0e40;
    color: #fff;
    display: flex;
    flex-direction: column;
    overflow: hidden;
}

.sidebar-header {
    padding: 16px 16px 8px;
    border-bottom: 1px solid rgba(255,255,255,0.15);
}

.sidebar-header h3 {
    margin: 0;
    font-size: 1.1rem;
    font-weight: 700;
}

.channel-list {
    list-style: none;
    padding: 0;
    margin: 0;
    overflow-y: auto;
    flex: 1;
}

.channel-item {
    padding: 8px 16px;
    cursor: pointer;
    position: relative;
    transition: background 0.15s;
}

.channel-item:hover {
    background: rgba(255,255,255,0.08);
}

.channel-item.active {
    background: rgba(255,255,255,0.18);
}

.channel-name {
    font-weight: 600;
    font-size: 0.95rem;
}

.channel-description {
    font-size: 0.75rem;
    color: rgba(255,255,255,0.6);
    white-space: nowrap;
    overflow: hidden;
    text-overflow: ellipsis;
    margin-top: 2px;
}

.unread-badge {
    position: absolute;
    top: 10px;
    right: 12px;
    background: #e01e5a;
    color: #fff;
    font-size: 0.7rem;
    font-weight: 700;
    padding: 2px 7px;
    border-radius: 10px;
    min-width: 18px;
    text-align: center;
}

/* ─── Main Message Area ─── */
.chat-main {
    width: 55%;
    display: flex;
    flex-direction: column;
    background: #fff;
    border-right: 1px solid #e0e0e0;
    transition: width 0.2s;
}

.chat-main-full {
    width: 80%;
    border-right: none;
}

.main-header {
    padding: 12px 20px;
    border-bottom: 1px solid #e0e0e0;
    flex-shrink: 0;
}

.main-header h2 {
    margin: 0;
    font-size: 1.15rem;
    font-weight: 700;
}

.main-header-desc {
    font-size: 0.8rem;
    color: #616061;
    margin-top: 2px;
    display: block;
}

.no-channel-selected {
    display: flex;
    align-items: center;
    justify-content: center;
    height: 100%;
    color: #888;
    font-size: 1.1rem;
}

/* ─── Message List ─── */
.message-list {
    flex: 1;
    overflow-y: auto;
    padding: 12px 20px;
}

.loading-indicator {
    text-align: center;
    color: #999;
    padding: 8px;
    font-size: 0.85rem;
}

.message-row {
    padding: 6px 8px;
    border-radius: 6px;
    position: relative;
    margin-bottom: 2px;
    transition: background 0.12s;
}

.message-row:hover {
    background: #f8f8f8;
}

.message-header {
    display: flex;
    align-items: baseline;
    gap: 8px;
}

.message-author {
    font-weight: 700;
    font-size: 0.95rem;
}

.message-time {
    font-size: 0.75rem;
    color: #999;
}

.message-content {
    font-size: 0.93rem;
    line-height: 1.45;
    margin-top: 2px;
    white-space: pre-wrap;
    word-break: break-word;
}

/* ─── Reactions ─── */
.reaction-row {
    display: flex;
    gap: 4px;
    margin-top: 4px;
    flex-wrap: wrap;
}

.reaction-badge {
    background: #f0f0f0;
    border: 1px solid #ddd;
    border-radius: 12px;
    padding: 2px 8px;
    font-size: 0.8rem;
    cursor: pointer;
    display: flex;
    align-items: center;
    gap: 3px;
    transition: background 0.15s;
}

.reaction-badge:hover {
    background: #e0e8ff;
    border-color: #7b8ec9;
}

/* ─── Thread Link ─── */
.thread-link {
    background: none;
    border: none;
    color: #1264a3;
    font-size: 0.8rem;
    cursor: pointer;
    padding: 4px 0 0;
    font-weight: 600;
}

.thread-link:hover {
    text-decoration: underline;
}

/* ─── Message Hover Actions ─── */
.message-actions {
    position: absolute;
    top: -8px;
    right: 8px;
    display: flex;
    gap: 2px;
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 2px 4px;
